fn solve(landStartTime: Vec<i64>, landDuration: Vec<i64>, waterStartTime: Vec<i64>, waterDuration: Vec<i64>) -> i64 {
    let n = landStartTime.len();
    let m = waterStartTime.len();
    let mut min_time = std::i64::MAX;

    for i in 0..n {
        let land_end = landStartTime[i] + landDuration[i];
        for j in 0..m {
            let water_end = waterStartTime[j] + waterDuration[j];

            let time1 = land_end.max(waterStartTime[j]) + waterDuration[j];
            let time2 = water_end.max(landStartTime[i]) + landDuration[i];

            let candidate = time1.min(time2);
            if candidate < min_time {
                min_time = candidate;
            }
        }
    }

    min_time
}
```

### Explanation
